import{_ as e,o as a,c as o,ag as l}from"./chunks/framework-C5-Jzrz4.js";const c=JSON.parse('{"title":"ColPage 分栏页面","description":"@vben/common-ui 的左右分栏页面容器，基于 Page 和可拖拽分栏实现","frontmatter":{"title":"ColPage 分栏页面","description":"@vben/common-ui 的左右分栏页面容器，基于 Page 和可拖拽分栏实现","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"scripts/components/common-ui/col-page.md","filePath":"scripts/components/common-ui/col-page.md","lastUpdated":null}');const i=e({name:"scripts/components/common-ui/col-page.md"},[["render",function(e,c,i,d,t,r){return a(),o("div",null,[...c[0]||(c[0]=[l('<h1 id="colpage" tabindex="-1"><code>ColPage</code> <a class="header-anchor" href="#colpage" aria-label="Permalink to &quot;`ColPage`&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>ColPage</code> 是面向管理页的分栏容器，底层组合了 <code>Page</code> 和 <code>ResizablePanelGroup</code>。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>左侧筛选区、树区、列表区</li><li>右侧明细区、编辑区、内容区</li><li>需要可折叠、可拖拽分割线的页面</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>packages/effects/common-ui/src/components/col-page/index.ts</code></li><li><code>packages/effects/common-ui/src/components/col-page/col-page.vue</code></li><li><code>packages/effects/common-ui/src/components/col-page/types.ts</code></li><li><code>packages/effects/common-ui/src/components/page/page.vue</code></li></ul><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><h3 id="导出" tabindex="-1">导出 <a class="header-anchor" href="#导出" aria-label="Permalink to &quot;导出&quot;">​</a></h3><ul><li><code>ColPage</code></li><li><code>ColPageProps</code></li></ul><h3 id="关键能力" tabindex="-1">关键能力 <a class="header-anchor" href="#关键能力" aria-label="Permalink to &quot;关键能力&quot;">​</a></h3><ul><li>左右两栏分别使用 <code>leftWidth</code> 和 <code>rightWidth</code> 控制默认宽度。</li><li><code>leftCollapsible</code>、<code>rightCollapsible</code> 控制面板是否可折叠。</li><li><code>resizable</code> 控制中间拖拽分割线是否显示。</li><li><code>splitLine</code> 和 <code>splitHandle</code> 用于控制分割线样式。</li></ul><h3 id="对-page-的继承" tabindex="-1">对 <code>Page</code> 的继承 <a class="header-anchor" href="#对-page-的继承" aria-label="Permalink to &quot;对 `Page` 的继承&quot;">​</a></h3><p><code>ColPageProps</code> 直接继承 <code>PageProps</code>，因此页面标题、描述、底部等能力仍由 <code>Page</code> 提供。</p><h3 id="暴露方法" tabindex="-1">暴露方法 <a class="header-anchor" href="#暴露方法" aria-label="Permalink to &quot;暴露方法&quot;">​</a></h3><ul><li><code>expandLeft()</code></li><li><code>collapseLeft()</code></li></ul><h2 id="使用方式与注意事项" tabindex="-1">使用方式与注意事项 <a class="header-anchor" href="#使用方式与注意事项" aria-label="Permalink to &quot;使用方式与注意事项&quot;">​</a></h2><ul><li>左侧区域通过 <code>left</code> 插槽渲染，默认内容通过默认插槽渲染。</li><li>当需要按业务状态控制左侧折叠时，可通过 <code>ref</code> 调用暴露方法。</li><li>这是页面容器，不是通用布局库，不建议脱离页面级场景单独使用。</li></ul>',18)])])}]]);export{c as __pageData,i as default};
